return msg;

const windowMs = 60000;
const now = Date.now();
const history = flow.get('history') || [];
const items = (Array.isArray(msg.payload) ? msg.payload : [msg.payload]).filter(Boolean);
for (const item of items) { history.push({ ts: now, item }); }
const recent = history.filter(entry => now - entry.ts <= windowMs);
flow.set('history', recent);
const temps = recent.map(entry => entry.item?.data?.sensors?.temperature).filter(v => typeof v === 'number');
const hums = recent.map(entry => entry.item?.data?.sensors?.humidity).filter(v => typeof v === 'number');
const avg = arr => arr.length ? arr.reduce((sum, value) => sum + value, 0) / arr.length : 0;
msg.payload = {
  floor: 'f01',
  timestamp: now,
  windowSeconds: 60,
  temperatureAvg: Number(avg(temps).toFixed(2)),
  humidityAvg: Number(avg(hums).toFixed(2)),
  sampleCount: recent.length
};
return msg;

